// Mappe les noms de colonnes techniques vers des labels humains.
// Champ absent du map → on garde le nom brut (mais formaté lisible).
const LABELS = {
  // reservistes - identite
  prenom: 'Prénom',
  nom: 'Nom',
  email: 'Adresse courriel',
  telephone: 'Téléphone',
  telephone_secondaire: 'Téléphone secondaire',
  date_naissance: 'Date de naissance',
  // Adresse
  adresse: 'Adresse',
  code_postal: 'Code postal',
  ville: 'Ville',
  region: 'Région',
  // Contact urgence
  contact_urgence_nom: "Contact d'urgence (nom)",
  contact_urgence_telephone: "Contact d'urgence (téléphone)",
  contact_urgence_courriel: "Contact d'urgence (courriel)",
  contact_urgence_lien: "Contact d'urgence (lien)",
  // Statuts
  groupe: 'Groupe',
  statut: 'Statut',
  role: 'Rôle',
  antecedents_statut: 'Vérification des antécédents (statut)',
  antecedents_date_verification: 'Date vérification antécédents',
  antecedents_date_expiration: 'Date expiration antécédents',
  consentement_antecedents: 'Consentement antécédents',
  // Profil
  profession: 'Profession',
  groupe_sanguin: 'Groupe sanguin',
  problemes_sante: 'Problèmes de santé',
  conditions_medicales: 'Conditions médicales',
  allergies_alimentaires: 'Allergies alimentaires',
  allergies_autres: 'Autres allergies',
  experience_urgence_detail: "Expérience en urgence",
  autres_competences: 'Autres compétences',
  preference_tache: 'Préférence de tâche',
  preference_tache_commentaire: 'Préférence de tâche (commentaire)',
  // Compétences (arrays)
  competence_rs: 'Compétences en recherche-sauvetage',
  certificat_premiers_soins: 'Premiers soins',
  vehicule_tout_terrain: 'Véhicule tout-terrain',
  navire_marin: 'Navire/marin',
  permis_conduire: 'Permis de conduire',
  satp_drone: 'SATP / Drone',
  equipe_canine: 'Équipe canine',
  competences_securite: 'Compétences sécurité',
  competences_sauvetage: 'Compétences sauvetage',
  certification_csi: 'Certification SCI/ICS',
  communication: 'Communication',
  cartographie_sig: 'Cartographie SIG',
  operation_urgence: "Opération d'urgence",
  disponible_covoiturage: 'Disponibilité covoiturage',
  // Bottes/équipement
  grandeur_bottes: 'Grandeur de bottes',
  remboursement_bottes_date: 'Date remboursement bottes',
  // Camp
  camp_qualif_complete: 'Camp de qualification complété',
  groupe_recherche: 'Groupe de recherche',
  responsable_groupe: 'Responsable de groupe',
  // Connexion
  methode_connexion: 'Méthode de connexion (SMS/courriel)',
  // Consentements
  consent_photo: 'Consentement photo',
  consent_photos: 'Consentement photos',
  confidentialite: 'Confidentialité',
  j_ai_18_ans: '18 ans et plus',
  // Formations
  nom_formation: 'Formation',
  resultat: 'Résultat',
  etat_validite: 'Validité',
  date_reussite: 'Date de réussite',
  date_expiration: 'Date expiration',
  certificat_url: 'Fichier certificat',
  initiation_sc_completee: 'Initiation SC complétée',
  date_expiration_certificat: 'Date expiration certificat',
};

function humanize(field) {
  if (LABELS[field]) return LABELS[field];
  // Fallback : remplace _ par espaces et capitalise.
  return String(field || '').replace(/_/g, ' ').replace(/^./, c => c.toUpperCase());
}

function formatValue(v) {
  if (v === null || v === undefined) return '<em>(vide)</em>';
  if (Array.isArray(v)) {
    if (v.length === 0) return '<em>(aucune)</em>';
    return v.map(x => String(x)).join(', ');
  }
  if (typeof v === 'boolean') return v ? 'Oui' : 'Non';
  if (typeof v === 'object') return JSON.stringify(v);
  return String(v);
}

function tableLabel(t) {
  if (t === 'reservistes') return 'votre profil';
  if (t === 'formations_benevoles') return 'vos formations';
  if (t === 'dossier_reserviste') return 'votre dossier';
  return t;
}

const results = [];

for (const item of $input.all()) {
  const j = item.json;
  // Skip items invalides (cas où Postgres retourne 0 lignes mais propage un item bidon)
  if (!j || !j.destinataire_email) continue;
  const auteur = `${j.changed_by_prenom || ''} ${j.changed_by_nom || ''}`.trim() || 'Un administrateur';
  const date = new Date(j.derniere_modif).toLocaleString('fr-CA', {
    timeZone: 'America/Montreal',
    dateStyle: 'long',
    timeStyle: 'short',
  });

  // Grouper modifs par table pour un affichage plus propre
  const modifs = Array.isArray(j.modifs) ? j.modifs : [];
  const parTable = {};
  for (const m of modifs) {
    if (!parTable[m.table]) parTable[m.table] = [];
    parTable[m.table].push(m);
  }

  let blocsHtml = '';
  for (const [t, list] of Object.entries(parTable)) {
    blocsHtml += `<p style="margin: 16px 0 4px; font-weight: 600; color: #1e3a5f;">Modifications à ${tableLabel(t)} :</p>`;
    blocsHtml += '<ul style="margin: 4px 0 0 16px; padding: 0;">';
    for (const m of list) {
      blocsHtml += `<li style="margin: 6px 0;">`;
      blocsHtml += `<strong>${humanize(m.champ)}</strong> : `;
      blocsHtml += `${formatValue(m.avant)} <span style="color:#94a3b8;">→</span> ${formatValue(m.apres)}`;
      blocsHtml += `</li>`;
    }
    blocsHtml += '</ul>';
  }

  const html = `<!DOCTYPE html><html><body style="font-family: Arial, sans-serif; color: #1f2937; max-width: 600px; margin: 0 auto; padding: 24px;">
<h2 style="color: #1e3a5f; margin: 0 0 16px;">Modification à votre compte RIUSC</h2>
<p>Bonjour ${j.destinataire_prenom || ''},</p>
<p>Une modification a été apportée à votre compte le <strong>${date}</strong> par <strong>${auteur}</strong>.</p>
${blocsHtml}
<p style="margin-top: 24px; padding-top: 16px; border-top: 1px solid #e5e7eb; font-size: 13px; color: #6b7280;">
Si cette modification n'a pas été demandée par vous, contactez-nous immédiatement à <a href="mailto:info@riusc.ca">info@riusc.ca</a>.
</p>
<p style="margin-top: 16px; font-size: 13px; color: #6b7280;">— Équipe RIUSC<br><a href="https://portail.riusc.ca">portail.riusc.ca</a></p>
</body></html>`;

  results.push({
    json: {
      ...j,
      subject: 'RIUSC — Modification à votre profil',
      html,
    },
  });
}

return results;

