-- Marquer processed=true si SMTP a réussi (pas de champ 'error' dans l'item).
-- Si erreur (continueOnFail capture l'erreur dans $json.error), on incrémente retries.
DO $$
DECLARE
  v_error text := NULLIF('{{ String($json.error?.message || $json.error || "").replace(/'/g, "''") }}', '');
  v_queue_ids_csv text := '{{ $('Composer courriel HTML').item.json.queue_ids_csv }}';
BEGIN
  IF v_error IS NULL THEN
    UPDATE notif_audit_queue
    SET processed = true, processed_at = now()
    WHERE id::text = ANY(STRING_TO_ARRAY(v_queue_ids_csv, ','));
  ELSE
    UPDATE notif_audit_queue
    SET retries = retries + 1, error = v_error
    WHERE id::text = ANY(STRING_TO_ARRAY(v_queue_ids_csv, ','));
  END IF;
END $$;
